sys_script_include.script:
const ContactDetails = Class.create();
ContactDetails.prototype = {
    initialize: function (options) {
        this.transactionId = options.transactionId || gs.generateGUID();
        this.tableHelper = new Contact({
            transactionId: this.transactionId,
        });
        this.mappingFrontEndFieldsToDbFields = {
            sysId: "sys_id",
            userName: "user_name",
            firstName: "first_name",
            lastName: "last_name",
            email: "email",
            phone: "phone",
            title: "title",
            department: "department",
            company: "company",
        };
        this.logger = new Logger({
            transactionId: this.transactionId,
            source: this.type,
            includeTimeStamp: true,
            includeUserInfo: true,
            includeSessionId: true,
        });
    },

    getBreadcrumbsForRecord: function ({ displayValue, linkValue }) {
        return [
            ...ContactList.CONTACT_MAIN_LIST_BREADCRUMB,
            {
                title: displayValue,
                link: "?id=contact_details&scm_record_id=" + linkValue,
            },
        ];
    },

    getContactDataByUserName: function (userName) {
        try {
            const sysId = this.tableHelper.getRecordSysIdByUserName(userName);
            if (!sysId) {
                this.logger.warn({
                    method: "getContactDataByUserName",
                    userName: userName,
                    message: "No record found for userName",
                });
                return null;
            }
            return this.getContactDataBySysId(sysId);
        } catch (error) {
            this.logger.error({
                method: "getContactDataByUserName",
                userName: userName,
                message: "Error retrieving contact data",
                error: error.message,
            });
            return null;
        }
    },

    getContactDataBySysId: function (sysId) {
        try {
            const record = this.tableHelper.getRecordBySysId(sysId);
            if (!record) {
                this.logger.warn({
                    method: "getContactDataBySysId",
                    sysId: sysId,
                    message: "No record found for sysId",
                });
                return null;
            }
            const contactData = {};
            for (const [frontEndField, dbField] of Object.entries(
                this.mappingFrontEndFieldsToDbFields,
            )) {
                if (record.isValidField(dbField)) {
                    contactData[frontEndField] = record.getValue(dbField) || "";
                } else {
                    this.logger.warn({
                        method: "getContactDataBySysId",
                        field: dbField,
                        sysId: sysId,
                        message: "Invalid field",
                    });
                }
            }

            contactData.breadcrumbs = this.getBreadcrumbsForRecord({
                displayValue: record.getDisplayValue(),
                linkValue: record.getValue("user_name"),
            });

            return contactData;
        } catch (error) {
            this.logger.error({
                method: "getContactDataBySysId",
                sysId: sysId,
                message: "Error retrieving contact data",
                error: error.message,
            });
            return null;
        }
    },

    getMandatoryFields: function () {
        const dbMandatoryFields = this.tableHelper.getMandatoryFields();
        const frontEndMandatoryFields = [];
        for (const [frontEndField, dbField] of Object.entries(
            this.mappingFrontEndFieldsToDbFields,
        )) {
            if (dbMandatoryFields.includes(dbField)) {
                frontEndMandatoryFields.push(frontEndField);
            }
        }
        return frontEndMandatoryFields;
    },

    getTableName: function () {
        return this.tableHelper.getTableName();
    },

    validateContactData: function (data) {
        try {
            const mappedData = this._mapFrontEndToDbFields(data);
            const isValid = this.tableHelper.validateContactData(mappedData);
            if (!isValid) {
                this.logger.info({
                    method: "validateContactData",
                    data: data,
                    message: "Validation failed for data",
                });
            }
            return isValid;
        } catch (error) {
            this.logger.error({
                method: "validateContactData",
                data: data,
                message: "Error validating contact data",
                error: error.message,
            });
            return false;
        }
    },

    saveDataToContactRecord: function (sysId, data) {
        try {
            const mappedData = this._mapFrontEndToDbFields(data);
            return this.tableHelper.saveDataToRecord(sysId, mappedData);
        } catch (error) {
            this.logger.error({
                method: "saveDataToContactRecord",
                sysId: sysId,
                data: data,
                message: "Error saving contact record",
                error: error.message,
            });
            return false;
        }
    },

    saveDataToContactRecordByUserName: function (userName, data) {
        try {
            const sysId = this.tableHelper.getRecordSysIdByUserName(userName);
            if (!sysId) {
                this.logger.warn({
                    method: "saveDataToContactRecordByUserName",
                    userName: userName,
                    message: "No record found for userName",
                });
                return false;
            }
            return this.saveDataToContactRecord(sysId, data);
        } catch (error) {
            this.logger.error({
                method: "saveDataToContactRecordByUserName",
                userName: userName,
                data: data,
                message: "Error saving contact record",
                error: error.message,
            });
            return false;
        }
    },

    _mapFrontEndToDbFields: function (data) {
        const mappedData = {};
        for (const [frontEndField, dbField] of Object.entries(
            this.mappingFrontEndFieldsToDbFields,
        )) {
            if (data.hasOwnProperty(frontEndField)) {
                mappedData[dbField] = data[frontEndField];
            }
        }
        return mappedData;
    },

    type: "ContactDetails",
};
